    sym = r['Symbol']
    vol = float(r['AvgVol'])
    desc = desc_map.get(sym, "Unknown")
    
    # Try to extract company name
    # Heuristic: split by " specializes", " provides", " is", " offers", " harnesses", " dedicated", " based"
